/* NYC centre — note: Mapbox GL JS uses [longitude, latitude] order
   (standard GeoJSON format), which is the REVERSE of Leaflet. */
const NYC_CENTER   = [-73.985, 40.710];
const DEFAULT_ZOOM = 10;
const BUFFER_MI    = 0.5;   // 0.5-mile proximity threshold

/* Layer IDs for every data layer.
   In Mapbox GL JS we show/hide layers by ID using
   map.setLayoutProperty(id, 'visibility', 'visible'/'none')
   instead of Leaflet's addLayer / removeLayer approach. */
const ALL_DATA_LAYERS = [
  'nycha-layer',
  'buffer-fill',
  'buffer-line',
  'evac-glow',
  'evac-layer',
  'gap-layer',
  'priority-fill',
  'priority-line'
];

/* Which layers are visible for each step */
const STEP_LAYERS = {
  1: ['nycha-layer'],
  2: ['nycha-layer', 'buffer-fill', 'buffer-line', 'evac-glow', 'evac-layer', 'gap-layer'],
  3: ['buffer-fill', 'buffer-line', 'evac-glow', 'evac-layer', 'gap-layer'],
  4: ['gap-layer', 'priority-fill', 'priority-line']
};

let map;
let gapCount    = 0;
let currentStep = 0;


/* ============================================================
   5. UTILITY FUNCTIONS
============================================================ */

/* ── Haversine distance ──────────────────────────────────────
   Unchanged from original — calculates straight-line distance
   between two lat/lng points in miles.
──────────────────────────────────────────────────────────── */
function distanceMiles(lat1, lon1, lat2, lon2) {
  const R     = 3958.8;
  const toRad = deg => deg * Math.PI / 180;
  const dLat  = toRad(lat2 - lat1);
  const dLon  = toRad(lon2 - lon1);
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
    Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

/* Returns true if the NYCHA development is within 0.5 miles
   of at least one evacuation center */
function isWithinBuffer(nycha) {
  return evacData.some(c =>
    distanceMiles(nycha.latitude, nycha.longitude, c.latitude, c.longitude) <= BUFFER_MI
  );
}

/* ── GeoJSON helpers ─────────────────────────────────────────
   Mapbox GL JS works natively with GeoJSON — we convert our
   embedded data arrays into FeatureCollections to use as sources.
──────────────────────────────────────────────────────────── */

/* Convert an array of {latitude, longitude, ...} objects into
   a GeoJSON FeatureCollection of Point features.
   NOTE: GeoJSON uses [longitude, latitude] order. */
function toPointGeoJSON(dataArray) {
  return {
    type: 'FeatureCollection',
    features: dataArray.map(d => ({
      type: 'Feature',
      geometry: {
        type:        'Point',
        coordinates: [d.longitude, d.latitude]  // [lng, lat]
      },
      properties: {}
    }))
  };
}

/* Generate 0.5-mile buffer polygons around each evacuation center
   using Turf.js. Returns a GeoJSON FeatureCollection of polygons.
   This is more accurate than Leaflet's L.circle() because Turf
   accounts for the curvature of the Earth. */
function generateBufferGeoJSON() {
  const features = evacData.map(c => {
    const point    = turf.point([c.longitude, c.latitude]);
    const buffered = turf.buffer(point, BUFFER_MI, { units: 'miles', steps: 64 });
    return buffered;
  });
  return { type: 'FeatureCollection', features };
}

/* Convert the priority area bounding boxes into GeoJSON Polygons.
   Original format: [[lat1, lng1], [lat2, lng2]] → closed ring in GeoJSON. */
function generatePriorityGeoJSON() {
  const areas = [
    {
      label:  'South Bronx',
      bounds: [[40.808, -73.940], [40.842, -73.888]],
      note:   'High NYCHA density + limited evacuation center proximity'
    },
    {
      label:  'Southern Brooklyn',
      bounds: [[40.568, -74.025], [40.622, -73.935]],
      note:   'Coastal exposure + access gaps (Coney Island / Red Hook)'
    },
    {
      label:  'Southeast Queens',
      bounds: [[40.590, -73.810], [40.682, -73.738]],
      note:   'Farther from centralised evacuation infrastructure'
    },
    {
      label:  'Staten Island North Shore',
      bounds: [[40.492, -74.270], [40.558, -74.120]],
      note:   'Waterfront exposure + limited transit options'
    }
  ];

  return {
    type: 'FeatureCollection',
    features: areas.map(area => {
      const [[lat1, lng1], [lat2, lng2]] = area.bounds;
      return {
        type: 'Feature',
        properties: { label: area.label, note: area.note },
        geometry: {
          type: 'Polygon',
          coordinates: [[
            [lng1, lat1],
            [lng2, lat1],
            [lng2, lat2],
            [lng1, lat2],
            [lng1, lat1]   /* close the ring */
          ]]
        }
      };
    })
  };
}


/* ============================================================
   6. MAP INITIALISATION
   Creates the Mapbox GL JS map and kicks off all setup once
   the map style tiles have finished loading.

   Key differences from Leaflet:
   - interactive: false disables ALL user interaction in one option
   - All data layers must be added inside the map 'load' event
   - Center is [longitude, latitude] — the reverse of Leaflet
============================================================ */
function initMap() {
  map = new mapboxgl.Map({
    container:   'map',           /* the <div id="map"> in index.html */
    style:       'mapbox://styles/mapbox/light-v11',  /* minimal light basemap — similar to CartoDB Positron */
    center:      NYC_CENTER,      /* [longitude, latitude] */
    zoom:        DEFAULT_ZOOM,
    interactive: false            /* disables ALL user interaction:
                                     dragging, scrollWheelZoom, doubleClickZoom,
                                     keyboard, boxZoom, touchZoomRotate */
  });

  /* Everything that touches the map (adding sources, layers, etc.)
     must happen inside this 'load' event — before this fires,
     the map style isn't ready to accept data. */
  map.on('load', () => {
    buildAllLayers();       /* add all GeoJSON sources + styled layers */
    loadBoroughBoundaries();/* async: fetch borough polygons from NYC Open Data */

    document.getElementById('loading-overlay').classList.add('hidden');
    showStep(1);            /* activate step 1 immediately */
    setupScrollytelling();  /* start watching scroll position */
  });
}


/* ── Fetch borough boundaries from NYC Open Data ─────────────
   Same strategy as before — tries the live endpoint first,
   falls back to embedded simplified polygons if it fails.
   In Mapbox GL JS we update a source with .setData() rather
   than creating a new GeoJSON layer.
──────────────────────────────────────────────────────────── */
async function loadBoroughBoundaries() {
  function renderBorough(geojson) {
    /* Update the borough source that was already added in buildAllLayers() */
    if (map.getSource('borough-source')) {
      map.getSource('borough-source').setData(geojson);
    }
  }

  try {
    const res     = await fetch(BOROUGH_API);
    const geojson = await res.json();
    renderBorough(geojson);
    console.log('Borough boundaries loaded from NYC Open Data.');
  } catch (err) {
    console.warn('Borough fetch failed — using fallback polygons.', err);
    renderBorough(BOROUGH_FALLBACK);
  }
}


/* ============================================================
   7. BUILDING ALL MAP SOURCES AND LAYERS
   In Mapbox GL JS, the workflow is:
     1. addSource(id, { type: 'geojson', data: ... })
     2. addLayer({ id, type, source, paint, layout })

   All data layers start hidden (visibility: 'none').
   showStep() makes the right ones visible for each step.

   Borough layers are the exception — they are always visible.
============================================================ */
function buildAllLayers() {

  /* ── 1. Borough Boundaries ─────────────────────────────────
     Source starts empty; loadBoroughBoundaries() calls
     .setData() to fill it in once the fetch resolves.

     Mapbox data-driven styling lets us color each borough
     differently using a 'match' expression — much cleaner
     than Leaflet's onEachFeature loop.
  ──────────────────────────────────────────────────────────── */
  map.addSource('borough-source', {
    type: 'geojson',
    data: BOROUGH_FALLBACK   // render embedded boundaries immediately; upgrade if fetch succeeds
  });
 
  /* Borough color expression — reads the 'boro_name' property */
  const boroughColorExpression = [
    'match', ['get', 'boro_name'],
    'Manhattan',    '#4a90d9',
    'Brooklyn',     '#27ae60',
    'Queens',       '#e67e22',
    'Bronx',        '#8e44ad',
    'Staten Island','#c0392b',
    '#888888'       /* fallback */
  ];

  map.addLayer({
    id:     'borough-fill',
    type:   'fill',
    source: 'borough-source',
    paint:  {
      'fill-color':   boroughColorExpression,
      'fill-opacity': 0.07
    }
  });

  map.addLayer({
    id:     'borough-line',
    type:   'line',
    source: 'borough-source',
    paint:  {
      'line-color':   boroughColorExpression,
      'line-width':   1.8,
      'line-opacity': 0.5
    }
  });

/* ── Borough name labels ────────────────────────────────────
     Symbol layer renders the boro_name property as text,
     positioned at the visual centre of each borough polygon.
  ──────────────────────────────────────────────────────────── */
  map.addLayer({
    id:     'borough-labels',
    type:   'symbol',
    source: 'borough-source',
    layout: {
      'text-field':             ['get', 'BoroName'],  // reads boro_name from GeoJSON properties
      'text-font':              ['DIN Offc Pro Medium', 'Arial Unicode MS Regular'],
      'text-size':              13,
      'text-letter-spacing':    0.08,
      'text-transform':         'uppercase',
      'symbol-placement':       'point',
      'text-allow-overlap':     false,
      'text-ignore-placement':  false
    },
    paint: {
      'text-color':        '#0d1b2a',   /* --color-ink, matches your design */
      'text-halo-color':   'rgba(255, 255, 255, 0.85)',
      'text-halo-width':   2
    }
  });

  /* ── 2. Compute gap count ───────────────────────────────────
     Run the buffer analysis now so gapCount and the filtered
     array of gap developments are ready before adding layers.
  ──────────────────────────────────────────────────────────── */
  const gapDevelopments = nychaData.filter(d => !isWithinBuffer(d));
  gapCount = gapDevelopments.length;
  updateStatBox();

  /* ── 3. All NYCHA developments — blue dots (step 1) ─────────
     Circle layer: one dot per NYCHA development.
     Uses circle-color, circle-stroke-* for styling.
  ──────────────────────────────────────────────────────────── */
  map.addSource('nycha-source', {
    type: 'geojson',
    data: toPointGeoJSON(nychaData)
  });

  map.addLayer({
    id:     'nycha-layer',
    type:   'circle',
    source: 'nycha-source',
    layout: { visibility: 'none' },   /* hidden until showStep(1) */
    paint:  {
      'circle-radius':       5,
      'circle-color':        '#457b9d',   /* steel blue */
      'circle-stroke-width': 0.5,
      'circle-stroke-color': '#1a2744',   /* dark navy outline */
      'circle-opacity':      0.82
    }
  });


  /* ── 4. Evacuation center buffers (steps 2–3) ───────────────
     Turf.js generates accurate 0.5-mile geographic polygons —
     these are real circles on the earth's surface, not pixel circles.
     Split into fill + dashed outline layers (same visual as Leaflet).
  ──────────────────────────────────────────────────────────── */
  map.addSource('buffer-source', {
    type: 'geojson',
    data: generateBufferGeoJSON()
  });

  map.addLayer({
    id:     'buffer-fill',
    type:   'fill',
    source: 'buffer-source',
    layout: { visibility: 'none' },
    paint:  {
      'fill-color':   '#f4a261',
      'fill-opacity': 0.10
    }
  });

  map.addLayer({
    id:     'buffer-line',
    type:   'line',
    source: 'buffer-source',
    layout: { visibility: 'none' },
    paint:  {
      'line-color':     '#e76f51',
      'line-width':     1.2,
      'line-dasharray': [5, 5]
    }
  });


  /* ── 5. Evacuation centers (steps 2–3) ───────────────────────
     Two layered circles per center: a large blurred glow + a
     solid dot on top. This recreates the divIcon glow effect
     from Leaflet using Mapbox GL JS paint properties.
  ──────────────────────────────────────────────────────────── */
  map.addSource('evac-source', {
    type: 'geojson',
    data: toPointGeoJSON(evacData)
  });

  /* Glow: large, blurred, low-opacity circle */
  map.addLayer({
    id:     'evac-glow',
    type:   'circle',
    source: 'evac-source',
    layout: { visibility: 'none' },
    paint:  {
      'circle-radius':  14,
      'circle-color':   '#e76f51',
      'circle-opacity': 0.20,
      'circle-blur':    1
    }
  });

  /* Solid dot: smaller, fully opaque, with white stroke */
  map.addLayer({
    id:     'evac-layer',
    type:   'circle',
    source: 'evac-source',
    layout: { visibility: 'none' },
    paint:  {
      'circle-radius':       6,
      'circle-color':        '#e76f51',
      'circle-stroke-width': 2,
      'circle-stroke-color': '#ffffff',
      'circle-opacity':      0.9
    }
  });


  /* ── 6. NYCHA access-gap dots — red (steps 2–4) ──────────────
     Re-maps only the NYCHA developments NOT within any buffer.
     These represent the "access gap" — housing exposed to risk
     but far from designated evacuation help.
  ──────────────────────────────────────────────────────────── */
  map.addSource('gap-source', {
    type: 'geojson',
    data: toPointGeoJSON(gapDevelopments)
  });

  map.addLayer({
    id:     'gap-layer',
    type:   'circle',
    source: 'gap-source',
    layout: { visibility: 'none' },
    paint:  {
      'circle-radius':       6,
      'circle-color':        '#c1121f',   /* urgent red */
      'circle-stroke-width': 0.8,
      'circle-stroke-color': '#7a0619',
      'circle-opacity':      0.88
    }
  });


  /* ── 7. Priority area rectangles (step 4) ────────────────────
     Bounding boxes for the four highest-priority geographic
     clusters, rendered as filled + outlined polygons.
  ──────────────────────────────────────────────────────────── */
  map.addSource('priority-source', {
    type: 'geojson',
    data: generatePriorityGeoJSON()
  });

  map.addLayer({
    id:     'priority-fill',
    type:   'fill',
    source: 'priority-source',
    layout: { visibility: 'none' },
    paint:  {
      'fill-color':   '#023e8a',
      'fill-opacity': 0.12
    }
  });

  map.addLayer({
    id:     'priority-line',
    type:   'line',
    source: 'priority-source',
    layout: { visibility: 'none' },
    paint:  {
      'line-color':     '#023e8a',
      'line-width':     2,
      'line-dasharray': [6, 4]
    }
  });
}


/* ============================================================
   8. SHOWING / HIDING LAYERS BY STEP
   In Mapbox GL JS, we toggle visibility with:
     map.setLayoutProperty(layerId, 'visibility', 'visible'/'none')

   This is the equivalent of Leaflet's addLayer / removeLayer.
   Borough layers are not in the list — they stay visible always.
============================================================ */
function showStep(step) {
  if (step === currentStep) return;
  currentStep = step;

  /* Hide all data layers */
  ALL_DATA_LAYERS.forEach(id => {
    if (map.getLayer(id)) {
      map.setLayoutProperty(id, 'visibility', 'none');
    }
  });

  /* Show only the layers for this step */
  (STEP_LAYERS[step] || []).forEach(id => {
    if (map.getLayer(id)) {
      map.setLayoutProperty(id, 'visibility', 'visible');
    }
  });

  /* Fly to the appropriate map view.
     Note: flyTo uses [longitude, latitude] order, and duration
     is in milliseconds (vs. Leaflet's seconds). */
  switch (step) {

    case 1:
      /* All NYCHA developments — citywide overview */
      map.flyTo({ center: NYC_CENTER, zoom: DEFAULT_ZOOM, duration: 1300, essential: true });
      break;

    case 2:
      /* NYCHA + buffers + centers + access-gap highlights */
      map.flyTo({ center: NYC_CENTER, zoom: DEFAULT_ZOOM, duration: 1300, essential: true });
      break;

    case 3:
      /* Zoom in on South Brooklyn to show the access gap pattern */
      map.flyTo({ center: [-73.975, 40.635], zoom: 12, duration: 1400, essential: true });
      break;

    case 4:
      /* Access-gap dots + priority area rectangles — citywide */
      map.flyTo({ center: NYC_CENTER, zoom: DEFAULT_ZOOM, duration: 1300, essential: true });
      break;
  }

  updateLegend(step);
}


/* ============================================================
   9. UPDATING THE LEGEND
   Injects HTML into the map legend panel to match the layers
   currently visible. Identical to the original Leaflet version.
============================================================ */
function updateLegend(step) {
  const el = document.getElementById('map-legend');

  const legends = {

    1:
      `<span class="legend-title">NYCHA Developments</span>
       <div class="legend-item">
         <div class="legend-dot" style="background:#457b9d"></div>
         <span>NYCHA development</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#4a90d9;border-radius:2px;opacity:0.6"></div>
         <span>Borough boundary</span>
       </div>`,

    2:
      `<span class="legend-title">Evacuation Access</span>
       <div class="legend-item">
         <div class="legend-dot" style="background:#c1121f"></div>
         <span>NYCHA — outside 0.5 mi buffer</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#457b9d"></div>
         <span>NYCHA — within buffer</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#e76f51"></div>
         <span>Evacuation center</span>
       </div>
       <div class="legend-item">
         <div class="legend-dash" style="border-color:#e76f51"></div>
         <span>0.5-mile buffer</span>
       </div>`,

    3:
      `<span class="legend-title">Access Gap (zoomed)</span>
       <div class="legend-item">
         <div class="legend-dot" style="background:#c1121f"></div>
         <span>NYCHA outside buffer</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#e76f51"></div>
         <span>Evacuation center</span>
       </div>
       <div class="legend-item">
         <div class="legend-dash" style="border-color:#e76f51"></div>
         <span>0.5-mile buffer</span>
       </div>`,

    4:
      `<span class="legend-title">Planning Priority</span>
       <div class="legend-item">
         <div class="legend-dot" style="background:#023e8a;border-radius:2px"></div>
         <span>High-priority areas</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#c1121f"></div>
         <span>NYCHA outside buffer</span>
       </div>`
  };

  el.innerHTML = legends[step] || '';
}


/* ============================================================
   10. STAT BOX
   Fills in the statistics callout in Step 2's card.
   Unchanged from original.
============================================================ */
function updateStatBox() {
  const box = document.getElementById('stat-box-gap');
  if (!box) return;
  const pct = Math.round((gapCount / nychaData.length) * 100);
  box.innerHTML =
    `<span class="stat-number">${gapCount}</span>` +
    `NYCHA developments — ${pct}% of those mapped — ` +
    `are more than 0.5 miles from a hurricane evacuation center.`;
}


/* ============================================================
   11. SCROLLYTELLING — IntersectionObserver
   Unchanged from original. Watches each .step element and
   calls showStep(n) when one enters the viewport's middle zone.
============================================================ */
function setupScrollytelling() {
  const steps = document.querySelectorAll('.step');

  const observer = new IntersectionObserver(
    entries => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const n = parseInt(entry.target.dataset.step, 10);
          steps.forEach(s => s.classList.remove('is-active'));
          entry.target.classList.add('is-active');
          showStep(n);
        }
      });
    },
    { rootMargin: '-20% 0px -40% 0px', threshold: 0 }
  );

  steps.forEach(s => observer.observe(s));
}


/* ============================================================
   12. ENTRY POINT
   DOMContentLoaded fires once the HTML is parsed.
   initMap() creates the map; everything else is triggered
   from inside map.on('load') in initMap().
============================================================ */
document.addEventListener('DOMContentLoaded', () => {
  initMap();
});